    int mat[2][W+1];
    int i = 0;
    while(i < n) {
        int j = 0;
        if(i % 2 != 0) {
            while(++j <= W) {
                if(wt[i] <= j && j - wt[i] < W) {
                    mat[1][j] = std::max(val[i] + mat[0][j - wt[i]], mat[0][j]);
